  ('social-worker-moex-05490', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'essay', '請說明何謂非反應式研究（non-reactive research），並且舉例說明那些研究方法是
屬於非反應式研究？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "8a86e172f0f5", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05491', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '在研究過程中，透過研究工具如問卷或訪問稿蒐集資料，這是一系列從無到有的過程，如果要測量一些 概念或變項，必須經過形成概念與測量的過程，下列那一過程正確？', '["抽象構念→操作定義→概念化→名目定義→實際測量", "抽象構念→概念化→名目定義→操作定義→實際測量", "抽象構念→名目定義→操作定義→概念化→實際測量", "抽象構念→名目定義→概念化→操作定義→實際測量"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "8a86e172f0f5", "answer_pdf_sha1": "58115afe2e3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05492', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列那一個統計方法，適合處理「次數資料」的假設檢定？', '["F檢定", "t檢定", "χ2檢定", "U檢定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "8a86e172f0f5", "answer_pdf_sha1": "58115afe2e3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05493', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '在統計假設檢定裡，檢定之前我們會先設定顯著水準α，並根據樣本資料計算檢定的統計量，再檢視此 統計量在虛無假設成立的情況下屬於這個分配的機率P（P-value或P值）。下列有關P與α敘述，何者 錯誤？', '["α是判斷樣本統計量是否因機會產生的門檻機率，在檢定前必須確定", "在固定的顯著水準α下，雙尾檢定與單尾檢定的臨界點是不同的", "根據同一批資料，在單尾或雙尾檢定其P值是相同的", "當P>α時，檢定的結果須拒絕虛無假設"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "8a86e172f0f5", "answer_pdf_sha1": "58115afe2e3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05494', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關「調查研究方法」的敘述，何者錯誤？', '["相較於面對面訪問與電話訪問，郵寄問卷費用較為節省", "如果要獲得即時發生事件的資料，可以考慮使用電話訪問調查法", "面對面訪問的完成率通常是百分之百", "集體填答問卷回收率高"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "8a86e172f0f5", "answer_pdf_sha1": "58115afe2e3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05495', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關「焦點團體」的敘述，何者錯誤？', '["焦點團體須選擇一群跟討論主體相關的人進行討論", "焦點團體參與者通常約8～12人最多不超過15人", "焦點團體需要表達自己的想法，最好能主導焦點討論的走向", "焦點團體需要有一個主持人作為發言討論的調節者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "8a86e172f0f5", "answer_pdf_sha1": "58115afe2e3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05496', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '典範（paradigm）是指型塑我們觀察及了解事情的基本模式或參考架構，下列有關研究典範的敘述，何者 正確？', '["當我們觀察或理解現實時，實證主義典範強調追求對現實主觀的理解", "社會建構典範強調完全的客觀", "後現代主義典範反對有客觀現實存在這件事", "對女性主義典範者而言，做研究是她們的主要目的"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "8a86e172f0f5", "answer_pdf_sha1": "58115afe2e3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05497', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '量化研究與質性研究有不同的抽樣方法取得研究樣本，下列那一抽樣方法較適合量化研究抽樣？', '["配額抽樣", "系統抽樣", "理論抽樣", "滾雪球抽樣"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "8a86e172f0f5", "answer_pdf_sha1": "58115afe2e3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05498', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關測量誤差的敘述，何者錯誤？', '["拿成人的問卷去讓小學童作答，學童可能不懂一些專有名詞而隨意作答，是屬於「隨機誤差」", "受訪者因問卷過於冗長，問卷的後半部不加思索快速完成作答，是屬於「隨機誤差」", "受訪者因為愛面子，傾向於以社會期望的方式回答，是屬於「系統誤差」", "「系統誤差」影響測量的「信度」，「隨機誤差」影響測量的「效度」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "8a86e172f0f5", "answer_pdf_sha1": "58115afe2e3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05499', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '在貧富差距很大的國家，有很多低所得的國民，有較少的中產階級，有為數更少的富裕階級，這個國家 國民所得的分配，最有可能是下列何種分配狀況？', '["常態分配（平均數=中位數=眾數）", "高峰在左，長尾在右的右偏分配（眾數<中位數<平均數）", "高峰在右，長尾在左的左偏分配（平均數<中位數<眾數）", "雙峰分配（有兩個眾數的分配）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "8a86e172f0f5", "answer_pdf_sha1": "58115afe2e3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
